insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:3-6-training-and-development:exam:6ba4a028', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q8", "question": "One benefit to Gina of staff development is:", "options": ["Higher profits", "Increased retention of farm workers", "More opportunities for promotion", "The animals will be better cared for"], "caseStudy": "Gina is an employee on a dairy farm.", "hint": "The question asks about a benefit to GINA — the employee — not to the farm business.", "starter": "The answer is C because staff development gives Gina..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5><p><strong>Why C is correct:</strong> Staff development helps Gina gain qualifications and skills that could lead to promotion — a direct personal benefit to the employee.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Higher profits is a benefit to the dairy farm (the business), not to Gina personally.</li><li><strong>B — Wrong:</strong> Increased retention is a benefit to the business — it means the farm keeps its workers, not something that directly benefits Gina.</li><li><strong>D — Wrong:</strong> Better animal care is an operational outcome for the farm — not a personal benefit to Gina as an individual employee.</li></ul></div>", "modelAnswer": "C — More opportunities for promotion. Staff development helps Gina gain new qualifications and skills, making her more eligible for promotion to a more senior role with higher pay — a direct personal benefit."}'::jsonb),
('business:3-6-training-and-development:exam:2a27c899', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q9", "question": "What is the most likely reason for this digital communication training?", "options": ["The company is trying to reduce employee retention", "The company needs to reduce the productivity of its sales staff", "The company wants workers to enjoy using social media during their breaks", "The company wishes to encourage more of its workforce to work from home"], "caseStudy": "A telesales company has arranged digital communication training for all relevant employees.", "hint": "Think about what digital communication enables — remote working requires digital tools to communicate effectively.", "starter": "The answer is D because digital communication skills allow employees to..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5><p><strong>Why D is correct:</strong> Digital communication tools (video calls, emails, messaging platforms) are essential for remote working. A telesales company training staff in digital communication is most likely preparing them to work effectively from home.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Businesses want to increase retention (keep staff), not reduce it.</li><li><strong>B — Wrong:</strong> Businesses train staff to increase productivity, not reduce it.</li><li><strong>C — Wrong:</strong> Social media for personal use during breaks is not a business training priority and would be an unusual reason to arrange formal training.</li></ul></div>", "modelAnswer": "D — The company wishes to encourage more of its workforce to work from home. Digital communication training equips telesales staff with the skills needed to communicate effectively with colleagues and customers remotely."}'::jsonb),
('business:3-6-training-and-development:exam:ff62252a', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q10", "question": "The percentage change in the training costs is approximately equal to:", "options": ["–20.6%", "–17.1%", "17.1%", "20.6%"], "caseStudy": "A firm has changed the way it trains its employees. Instead of using off-the-job training (£82,000) it now uses on-the-job training (£68,000).", "hint": "Percentage change = (New − Old) ÷ Old × 100. The original (old) cost is off-the-job: £82,000.", "starter": "Percentage change = (68,000 − 82,000) ÷ 82,000 × 100 = ..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — −17.1%</h5><p><strong>Calculation:</strong></p><ul><li>Change = £68,000 − £82,000 = −£14,000</li><li>Percentage change = −14,000 ÷ 82,000 × 100 = −17.07% ≈ −17.1%</li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (−20.6%):</strong> This is calculated using the new cost as the denominator (14,000 ÷ 68,000 × 100) — incorrect. Always divide by the original value.</li><li><strong>C (17.1%):</strong> Correct calculation but wrong sign — costs have decreased, not increased.</li><li><strong>D (20.6%):</strong> Wrong calculation and wrong sign.</li></ul></div>", "modelAnswer": "B — −17.1%. Percentage change = (68,000 − 82,000) ÷ 82,000 × 100 = −14,000 ÷ 82,000 × 100 ≈ −17.1%. The negative sign shows costs have decreased."}'::jsonb),
('business:3-6-training-and-development:exam:cc8fa9d0', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which of the following is a benefit to a business of using off-the-job training?", "options": ["Large numbers of employees can be trained at the same time", "Likely to be cheaper than on-the-job training", "The training can take place while the employee is working", "Workers need to be paid for time spent doing off-the-job training"], "hint": "Think about what off-the-job training can do that individual on-the-job training cannot.", "starter": "The answer is A because off-the-job training at a venue or training centre can..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5><p><strong>Why A is correct:</strong> Off-the-job training at a college or training centre can accommodate multiple employees simultaneously — unlike on-the-job training which is typically one-on-one.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>B — Wrong:</strong> Off-the-job training is typically more expensive than on-the-job training due to course fees, travel, and accommodation costs.</li><li><strong>C — Wrong:</strong> This describes on-the-job training, not off-the-job training.</li><li><strong>D — Wrong:</strong> This is a disadvantage of off-the-job training, not a benefit — the business still pays wages while workers are not producing output.</li></ul></div>", "modelAnswer": "A — Large numbers of employees can be trained at the same time. Off-the-job training venues (e.g. colleges, training centres) can train groups of employees simultaneously, which on-the-job training (typically one-on-one) cannot achieve."}'::jsonb),
('business:3-6-training-and-development:exam:5ed2aba0', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'exam', 'mcq', 1, '{"num": "Q14", "question": "One benefit to a hospital of encouraging staff development is:", "options": ["Increased skill shortages", "Improved patient care", "Lower morale of doctors and nurses", "More medical staff can be employed"], "hint": "Think about what happens when hospital staff are better trained and qualified — what does that mean for the people they care for?", "starter": "The answer is B because when hospital staff develop their skills..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5><p><strong>Why B is correct:</strong> When hospital staff develop their skills through qualifications and professional development, the quality of their work improves — leading directly to better care for patients.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Staff development reduces skill shortages (by building skills internally), not increases them.</li><li><strong>C — Wrong:</strong> Development should improve morale (workers feel valued), not lower it.</li><li><strong>D — Wrong:</strong> Staff development is about improving the skills of existing staff, not directly leading to hiring more staff.</li></ul></div>", "modelAnswer": "B — Improved patient care. When hospital staff such as doctors and nurses undertake professional development and gain higher qualifications, their knowledge and clinical skills improve — leading to better treatment outcomes and higher quality care for patients."}'::jsonb),
('business:3-6-training-and-development:mcq:4a06c2c1', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "What is the main difference between training and development?", "options": ["Training is long-term and development is short-term", "Training is job-specific and short-term; development is about long-term potential", "Development only involves on-the-job activities", "Training always leads to a qualification"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Training is short-term and focused on a specific job or task. Development is longer-term and about growing the overall potential of the worker for future roles."}'::jsonb),
('business:3-6-training-and-development:mcq:a0784f89', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following is a feature of off-the-job training?", "options": ["The worker continues to produce goods or services whilst training", "It is a cheaper way of training workers than paying for them to go on courses", "Workers are trained in a college or training centre away from where they do the work", "It never leads to a qualification for the worker"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Off-the-job training takes place away from the employee''s normal duties — at an external venue such as a college or training centre. A is on-the-job, B is wrong (off-the-job is more expensive), D is false (off-the-job often leads to qualifications)."}'::jsonb),
('business:3-6-training-and-development:mcq:fa08bfe9', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a benefit to a golfing equipment retailer of training its sales assistants?", "options": ["To help staff give advice on which golf clubs to buy", "To increase the sales of golf umbrellas and waterproof clothing", "To motivate staff to assist customers who are trying on golf shoes", "To reduce the time it takes to make golf bags and golf trolleys"]}'::jsonb, '{"answer": 3, "explain": "Correct: D. A retailer doesn''t make golf bags — it sells them. Training sales assistants would not reduce manufacturing time because retail staff don''t manufacture products. A, B, and C are all genuine benefits of training retail staff."}'::jsonb),
('business:3-6-training-and-development:mcq:93ac8f1d', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "What is induction training?", "options": ["Training to help workers gain a vocational qualification", "Long-term development to realise a worker''s potential", "Training to introduce a new worker to the business and workplace", "On-the-job training delivered by an experienced colleague"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Induction training is specifically for new employees to help them settle into the workplace — meeting colleagues, learning health and safety rules, and understanding the culture of the business. It is NOT about teaching job skills."}'::jsonb),
('business:3-6-training-and-development:mcq:21059a6e', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of using on-the-job training to train new sales assistants at a petrol station?", "options": ["Likely to be more expensive than sending the employees on a training course", "Motorists may experience lower standards of customer service", "No petrol can be sold while the training takes place", "The employees will be trained on different equipment to that at the garage"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. A trainee serving real customers may make mistakes, leading to lower service quality. A is wrong — on-the-job is cheaper. C is wrong — petrol can still be sold. D is wrong — on-the-job uses the actual workplace equipment."}'::jsonb),
('business:3-6-training-and-development:mcq:059b1e4c', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a form of staff development?", "options": ["Academic qualifications", "Apprenticeships", "Induction", "Vocational qualifications"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Induction is a form of training — it is short-term and designed to introduce a new worker to the business. Staff development (academic qualifications, apprenticeships, vocational qualifications) is long-term and aimed at realising the worker''s future potential."}'::jsonb),
('business:3-6-training-and-development:mcq:9539b4f4', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following is a feature of professional development?", "options": ["It is a kind of short-term training", "It is designed to realise the potential of a worker in the long-term interests of the business and the worker", "It is designed to improve the skills of the worker to do a specific task", "It usually involves on-the-job training only"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Professional development is long-term and is about realising the potential of the worker — it may lead to vocational or academic qualifications. A and C describe training. D is false — professional development often includes off-the-job study at college or university."}'::jsonb),
('business:3-6-training-and-development:mcq:21da89ac', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "One benefit to Gina, an employee on a dairy farm, of staff development is:", "options": ["Higher profits for the farm", "Increased retention of farm workers", "More opportunities for promotion", "The animals will be better cared for"]}'::jsonb, '{"answer": 2, "explain": "Correct: C. Staff development benefits the individual worker — gaining qualifications and skills may lead to promotion opportunities. A and B are benefits to the business, not the employee. D relates to animal welfare, not a personal benefit to Gina."}'::jsonb),
('business:3-6-training-and-development:mcq:5ed2aba0', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "One benefit to a hospital of encouraging staff development is:", "options": ["Increased skill shortages", "Improved patient care", "Lower morale of doctors and nurses", "More medical staff can be employed"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. When hospital staff are developed through training and qualifications, their skills improve — leading directly to improved patient care. A is the opposite of a benefit. C is wrong — development improves morale. D is unrelated to development."}'::jsonb),
('business:3-6-training-and-development:mcq:d2048c4f', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following statements about apprenticeships is true?", "options": ["A vocational qualification is specific to a particular type of job", "An academic qualification prepares a worker for work in a specific business", "An apprenticeship is offered to senior managers who want to develop their skills further", "An apprenticeship involves only studying at university"]}'::jsonb, '{"answer": 0, "explain": "Correct: A. Vocational qualifications are job-specific — they relate to a particular occupation. B is wrong — academic qualifications are more general. C is wrong — apprenticeships are aimed at developing workers in a role, not exclusively senior managers. D is wrong — apprenticeships combine workplace training with college study."}'::jsonb),
('business:3-6-training-and-development:mcq:cd5a41a2', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "A firm switches from off-the-job training (costing £82,000) to on-the-job training (costing £68,000). What is the approximate percentage change in training costs?", "options": ["–20.6%", "–17.1%", "17.1%", "20.6%"]}'::jsonb, '{"answer": 1, "explain": "Correct: B. Percentage change = (68,000 − 82,000) / 82,000 × 100 = −14,000 / 82,000 × 100 ≈ −17.1%. The negative sign shows a decrease in cost."}'::jsonb),
('business:3-6-training-and-development:mcq:cc8fa9d0', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit to a business of using off-the-job training?", "options": ["Large numbers of employees can be trained at the same time", "Likely to be cheaper than on-the-job training", "The training can take place while the employee is working", "Workers need to be paid for time spent doing off-the-job training"]}'::jsonb, '{"answer": 0, "explain": "Correct: A. Off-the-job training at a venue can accommodate larger groups simultaneously — a key advantage over one-on-one on-the-job training. B is wrong — off-the-job is more expensive. C describes on-the-job training. D is a disadvantage, not a benefit."}'::jsonb),
('business:3-6-training-and-development:tf:d4b3f376', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "Induction training is designed to teach new workers the specific skills they need to do their job."}'::jsonb, '{"answer": false, "explain": "FALSE. Induction training is about introducing new employees to the workplace, colleagues, culture, and health and safety procedures — not teaching job-specific skills. Examiners frequently penalise students who confuse induction with skills training."}'::jsonb),
('business:3-6-training-and-development:tf:e677b3a5', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "On-the-job training is generally cheaper than off-the-job training for a business."}'::jsonb, '{"answer": true, "explain": "TRUE. On-the-job training has no travel, accommodation, or external course fees. The trainee also continues to produce goods or services during training, meaning the business still earns money."}'::jsonb),
('business:3-6-training-and-development:tf:ec19ebe9', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "Off-the-job training always leads to a qualification for the worker."}'::jsonb, '{"answer": false, "explain": "FALSE. Off-the-job training does not always lead to a qualification — it depends on the type of course. However, it is more likely to lead to qualifications than on-the-job training."}'::jsonb),
('business:3-6-training-and-development:tf:e903dd65', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "A disadvantage of professional development for a business is that once workers are better qualified, they may find it easier to secure jobs at other firms."}'::jsonb, '{"answer": true, "explain": "TRUE. This is a genuine retention risk for businesses. After investing in development, a more qualified worker may leave for a higher-paying role elsewhere, meaning the business does not get a return on its investment."}'::jsonb),
('business:3-6-training-and-development:tf:cce4a915', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "Apprenticeships are a form of staff development, not just a recruitment method."}'::jsonb, '{"answer": true, "explain": "TRUE. On this specification, apprenticeships appear in Section 3.6 as staff development. They involve developing existing employees who are already paid a wage, not just recruiting new ones cheaply."}'::jsonb),
('business:3-6-training-and-development:tf:48f8f43e', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "On-the-job training is suitable for all types of jobs, including those with significant safety risks."}'::jsonb, '{"answer": false, "explain": "FALSE. On-the-job training is not appropriate for safety-critical roles (e.g. cabin crew, surgeons) because mistakes made during training could endanger lives. Off-the-job simulation is required in these cases."}'::jsonb),
('business:3-6-training-and-development:tf:bd0f61c7', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "Development is more short-term and practical than training."}'::jsonb, '{"answer": false, "explain": "FALSE. It is the other way around. Training is short-term and practical; development is long-term and often includes both theoretical and practical learning to build the worker''s overall potential."}'::jsonb),
('business:3-6-training-and-development:tf:97d53e8f', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "A benefit of on-the-job training is that the trainee produces goods and services while learning, so the firm earns money during the training process."}'::jsonb, '{"answer": true, "explain": "TRUE. Because the trainee is working while learning, the business does not lose all of that worker''s productive output — a key financial advantage over off-the-job training where the worker is absent from their role entirely."}'::jsonb),
('business:3-6-training-and-development:tf:c937b73c', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "Academic qualifications are specific to a particular job role."}'::jsonb, '{"answer": false, "explain": "FALSE. Vocational qualifications are job-specific. Academic qualifications (e.g. GCSEs, A Levels, degrees) are more general and transferable across many different careers."}'::jsonb),
('business:3-6-training-and-development:tf:3420e98e', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "Businesses may train workers to solve skill shortages if the specialist labour they need cannot be found externally."}'::jsonb, '{"answer": true, "explain": "TRUE. If the market doesn''t supply enough skilled workers, businesses can train existing employees to fill those gaps internally — for example, training technicians to become fully qualified engineers."}'::jsonb),
('business:3-6-training-and-development:tf:cce82d56', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tf', 'tf', 1, '{"question": "The quality of on-the-job training depends on the communication skills and ability of the trainer."}'::jsonb, '{"answer": true, "explain": "TRUE. If the trainer has poor communication skills or bad habits, the trainee will learn them too. The quality of the training is only as good as the person delivering it — a key disadvantage of on-the-job training."}'::jsonb),
('business:3-6-training-and-development:learn:ee7b5345', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must know for the exam. Learn the distinction between each one carefully — examiners regularly test whether students can tell them apart.</p>\n  <ul>\n    <li><strong>Training:</strong> Short-term learning focused on improving a worker''s ability to do a specific job or task.</li>\n    <li><strong>Development:</strong> Long-term learning focused on growing a worker''s overall potential for future roles.</li>\n    <li><strong>On-the-job training:</strong> Training that takes place at the workplace while the employee is doing their job.</li>\n    <li><strong>Off-the-job training:</strong> Training that takes place away from the normal job, either on-site or at an external venue.</li>\n    <li><strong>Induction training:</strong> Training to introduce a new employee to the business, workplace, colleagues, and job role.</li>\n    <li><strong>Apprenticeship:</strong> A long-term development programme (typically 2–4 years) combining on-the-job and off-the-job learning, leading to a vocational qualification.</li>\n    <li><strong>Professional development:</strong> Long-term development of a worker through vocational or academic qualifications to realise their future potential.</li>\n    <li><strong>Vocational qualification:</strong> A job-specific qualification gained through a mix of practical and classroom learning (e.g. NVQ, Cambridge Technical).</li>\n    <li><strong>Academic qualification:</strong> A more general, theory-based qualification (e.g. GCSEs, A Levels, degrees).</li>\n    <li><strong>Productivity:</strong> Output per worker — a measure of how efficiently employees produce goods or services.</li>\n    <li><strong>Skills shortage:</strong> A situation where businesses cannot recruit workers with the skills they need.</li>\n    <li><strong>Retention:</strong> Keeping workers employed rather than them leaving to work elsewhere.</li>\n  </ul>", "question": "What is the key difference between training and development?", "options": ["Training is job-specific and short-term; development is long-term and broader", "They are exactly the same thing", "Training only happens off-the-job; development only happens on-the-job", "Development is for new employees only; training is for experienced staff only"]}'::jsonb, '{"answer": 0, "explain": "Training focuses on improving performance in the current job, in the short term. Development is broader and longer-term, focused on growing a worker''s overall future potential."}'::jsonb),
('business:3-6-training-and-development:learn:c6a6e477', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Training vs Development — What''s the Difference?", "reading": "<p>Students often mix these up. The distinction is subtle but important — examiners test it directly.</p>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">📚 Training</div>\n      <div class=\"pro-item\"><strong>Short-term</strong> — focused on improving performance in the current job now.</div>\n      <div class=\"pro-item\"><strong>Job-specific</strong> — teaches knowledge and skills needed to do a particular task.</div>\n      <div class=\"pro-item\"><strong>Practical focus</strong> — learning by doing, often hands-on.</div>\n      <div class=\"pro-item\"><strong>Example:</strong> A Starbucks barista learning to make different coffees from an experienced colleague.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">🎓 Development</div>\n      <div class=\"con-item\"><strong>Long-term</strong> — focused on improving the overall potential of the worker for future roles.</div>\n      <div class=\"con-item\"><strong>Person-centred</strong> — about growing the employee, not just the current job.</div>\n      <div class=\"con-item\"><strong>Theoretical + practical</strong> — includes academic knowledge as well as skills.</div>\n      <div class=\"con-item\"><strong>Example:</strong> Beaverbrooks jewellers offering a management development programme including home study, coaching, and promotion pathways.</div>\n    </div>\n  </div>\n  <p style=\"margin-top:12px\"><strong>Key rule:</strong> Both training and development can involve on- and off-the-job activities — it''s the <em>timeframe and purpose</em> that differs.</p>", "question": "A Starbucks barista learns to make different coffees from an experienced colleague. Is this training or development?", "options": ["Training — it''s short-term and job-specific", "Development — it''s about long-term growth", "Neither — it doesn''t count as either", "Both equally, with no real distinction"]}'::jsonb, '{"answer": 0, "explain": "This is training: it''s focused on the current job, is short-term, and teaches a specific practical skill needed right now — not the worker''s long-term potential."}'::jsonb),
('business:3-6-training-and-development:learn:1feec87e', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Why Do Businesses Train Their Workers?", "reading": "<p>Businesses invest in training for a wide range of reasons. In the exam, always link the reason to the business impact.</p>\n  <ul>\n    <li><strong>Improve productivity:</strong> Better-trained workers produce more output per hour, reducing unit costs and potentially increasing profit.</li>\n    <li><strong>Improve customer service:</strong> Well-trained staff give customers better advice and experiences, boosting sales and reputation.</li>\n    <li><strong>Solve skill shortages:</strong> If specialist workers can''t be recruited externally, training existing staff fills the gap.</li>\n    <li><strong>Improve motivation and retention:</strong> Workers feel valued when a business invests in them, making them less likely to leave and reducing costly recruitment cycles.</li>\n    <li><strong>Support business development:</strong> Training lets the business expand into new products or services.</li>\n    <li><strong>Induction of new workers:</strong> New employees need to understand the workplace, procedures, and culture before they can work effectively.</li>\n    <li><strong>Health and safety:</strong> Reduces accidents, legal claims, and bad publicity.</li>\n    <li><strong>New technology/products:</strong> Workers need updating when the business introduces new machinery, software, or product lines.</li>\n    <li><strong>Retraining:</strong> When technology replaces a job role, employees may be retrained to do a different role instead of being made redundant.</li>\n    <li><strong>Flexibility:</strong> Multiskilled workers can cover different roles, making the business more adaptable.</li>\n  </ul>", "question": "Why might a business retrain a worker instead of making them redundant when new technology is introduced?", "options": ["It is required by law in all cases", "It keeps an experienced worker in the business by moving them into a new role", "Retraining is always cheaper than hiring new staff regardless of circumstances", "It has no real benefit to the business"]}'::jsonb, '{"answer": 1, "explain": "When technology replaces a job role, retraining lets a business keep an experienced, loyal worker in a new position rather than losing them through redundancy — preserving knowledge and avoiding recruitment costs."}'::jsonb),
('business:3-6-training-and-development:learn:97d5f093', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "On-the-Job Training", "reading": "<p>On-the-job training takes place at the workplace while the employee is working. A common example is <strong>shadowing</strong>, where a new worker follows and learns from an experienced colleague.</p>\n  <div class=\"case-study-box\">\n    <h4>Case Study: Starbucks</h4>\n    <p>New baristas at Starbucks receive one-to-one on-the-job training. An experienced barista works alongside the new employee, showing them how to make the different coffees — from flat whites to Americanos. The trainee practises while serving real customers.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\"><strong>Individual training:</strong> Tailored to meet that specific worker''s needs.</div>\n      <div class=\"pro-item\"><strong>Cheaper:</strong> No travel, accommodation, or external course fees.</div>\n      <div class=\"pro-item\"><strong>Productive while training:</strong> The trainee produces goods/services during training, so the firm earns money.</div>\n      <div class=\"pro-item\"><strong>Business-specific:</strong> Trained to do the job the way the firm wants it done.</div>\n      <div class=\"pro-item\"><strong>Retention benefit:</strong> Skills may be specific to that firm, making it harder for the worker to leave — the business gets a return on its investment.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\"><strong>Trainer distracted:</strong> The trainer must leave their own work to help the trainee, so production may fall.</div>\n      <div class=\"con-item\"><strong>Quality risk:</strong> Work produced by a trainee may be poor, wasting resources or harming the firm''s reputation.</div>\n      <div class=\"con-item\"><strong>Trainer quality:</strong> If the trainer has poor communication skills or bad habits, the trainee learns them too.</div>\n      <div class=\"con-item\"><strong>No qualification:</strong> Workers typically don''t gain a recognised qualification from on-the-job training.</div>\n      <div class=\"con-item\"><strong>Limits portability:</strong> Firm-specific skills make it harder for the worker to find employment elsewhere if they lose their job.</div>\n      <div class=\"con-item\"><strong>Not suitable for groups:</strong> More effective one-on-one; difficult to scale.</div>\n    </div>\n  </div>", "question": "Why is on-the-job training often cheaper than off-the-job training?", "options": ["It avoids travel, accommodation, and course fees", "On-the-job training is always shorter in duration", "On-the-job trainers do not need to be paid", "It avoids the need for any equipment at all"]}'::jsonb, '{"answer": 0, "explain": "On-the-job training avoids external course fees, travel, and accommodation costs. The trainee can also produce goods or services while learning, meaning the business earns money during the training period — unlike off-the-job training."}'::jsonb),
('business:3-6-training-and-development:learn:227647d9', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Off-the-Job Training", "reading": "<p>Off-the-job training takes place <strong>away from the employee''s normal working duties</strong>. It may still be on company premises, but the worker is not doing their usual job. <br> <strong> Activities include:</strong></p>\n  <ul>\n  <li>\n    <p>\n      <strong>Lectures: </strong>\n      These are good for telling people about things and for giving information.\n      They are not good for improving skills.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Demonstrations: </strong>\n      The trainee watches someone show them how to do a job. These are good\n      because you learn from an expert. It is often necessary to practise the\n      work after the demonstration in order to develop the skills.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Role play or simulation: </strong>\n      The worker experiences a situation as if it were a real work situation.\n      The trainee practises the skills or practises how they would deal with the\n      situation.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Team-building: </strong>\n      A group performs tasks together in order to develop. It helps people learn\n      how to work well in teams and to appreciate the different qualities that\n      other people have. The tasks may or may not be connected to work. Non-work\n      connected activities can include outdoor pursuits.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Reading and reflecting on online materials: </strong>\n      The worker may have access to online training materials. Usually there are\n      tasks or exercises that must be completed to develop understanding of the\n      materials.\n    </p>\n  </li>\n</ul>\n        <div class=\"case-study-box\">\n    <h4>Case Study: Jet2.com</h4>\n    <p>Jet2.com trains its cabin crew entirely off-the-job at a dedicated training centre in Bradford. The centre has classrooms and full flight simulators. Trainees must earn their Cabin Crew Attestation — an industry-regulated qualification — before they are allowed to work on a real flight. Safety training on a live aircraft with passengers would be impossible and dangerous, making off-the-job simulation essential.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\"><strong>Expert trainers:</strong> Delivered by specialists who may introduce new ideas and best practice.</div>\n      <div class=\"pro-item\"><strong>Specialist equipment:</strong> Trainees can use purpose-built training equipment (e.g. flight simulators).</div>\n      <div class=\"pro-item\"><strong>Safe environment:</strong> Mistakes are made in training, not in the real workplace — critical for safety-critical roles.</div>\n      <div class=\"pro-item\"><strong>Focused learning:</strong> Workers are removed from operational distractions and can concentrate fully.</div>\n      <div class=\"pro-item\"><strong>Workers feel valued:</strong> Sending staff on courses signals the business is investing in them, boosting morale.</div>\n      <div class=\"pro-item\"><strong>Industry qualifications:</strong> Can lead to recognised, portable qualifications.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\"><strong>Expensive:</strong> Course fees, travel, and accommodation add up significantly.</div>\n      <div class=\"con-item\"><strong>Lost output:</strong> The worker is not producing goods or services while training.</div>\n      <div class=\"con-item\"><strong>Retention risk:</strong> Once qualified, workers may use their new skills to get a better-paid job elsewhere.</div>\n      <div class=\"con-item\"><strong>Not always business-specific:</strong> External trainers may not teach things exactly the way the business wants.</div>\n    </div>\n  </div>", "question": "Why does Jet2.com train its cabin crew entirely off-the-job using flight simulators?", "options": ["It is cheaper than on-the-job training", "A real flight is too dangerous for safety training", "Off-the-job training is required by law for all jobs", "Cabin crew prefer not to train at the airport"]}'::jsonb, '{"answer": 1, "explain": "Off-the-job training is essential here because mistakes can be made safely in a simulator rather than on a real flight with passengers — exactly the kind of safety-critical situation where off-the-job training is the right choice."}'::jsonb),
('business:3-6-training-and-development:learn:f1449306', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Induction Training", "reading": "<p>Induction training is for <strong>new employees only</strong>. Its purpose is NOT to teach job skills — it is to introduce the worker to the business, the workplace, and their colleagues so they can settle in quickly and work safely.</p>\n  <p><strong>⚠️ Common mistake:</strong> Many students describe induction as \"teaching new skills.\" This is wrong. Induction is about settling in, not skill-building. Examiners flagged this as a very common error.</p>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Benefits to the Worker</div>\n      <div class=\"pro-item\">Gets to know colleagues and feels welcome.</div>\n      <div class=\"pro-item\">Learns what is expected of them and the culture of the business.</div>\n      <div class=\"pro-item\">Finds out the layout of the workplace (toilets, canteen, emergency exits).</div>\n      <div class=\"pro-item\">Learns health and safety procedures, helping them work safely.</div>\n      <div class=\"pro-item\">May learn job-specific skills to begin their role.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✓ Benefits to the Business</div>\n      <div class=\"con-item\">Worker becomes productive more quickly — less time wasted settling in.</div>\n      <div class=\"con-item\">Reduced risk of accidents → fewer compensation claims and less bad publicity.</div>\n      <div class=\"con-item\">Worker feels valued → more likely to work hard and stay with the business.</div>\n      <div class=\"con-item\">Improved communication → worker understands the organisational structure and who to report to.</div>\n    </div>\n  </div>\n  <div class=\"case-study-box\">\n    <h4>Case Study: B&Q</h4>\n    <p>New B&Q employees are sent to the \"B&Q University\" (a dedicated training centre). They learn about the company''s history, aims, health and safety rules, pay structure, and promotion opportunities. This is a formal, off-the-job induction, though smaller businesses may conduct theirs on-site with a tour and introductions.</p>\n  </div>\n\n  <div class=\"case-study-box\">\n    <h4>Case Study: Christies Care</h4>\n    <p>All new employees complete a two-week residential\ntraining course. Skills taught include moving and handling patients, continence care,\nemergency first aid, infection control. Employees gain a care certificate before\nworking in a care home. </p>\n  </div>\n  \n  <p><strong>Cost reminder:</strong> Induction has a cost — wages are paid while the worker is not yet producing output, and someone must provide the training.</p>", "question": "What is the main PURPOSE of induction training?", "options": ["To teach the new worker advanced job-specific skills", "To help the new worker settle into the business quickly", "To replace the need for any other type of training", "To assess whether the worker should be promoted"]}'::jsonb, '{"answer": 1, "explain": "Induction is about settling a new worker in — introducing them to the business, the workplace layout, colleagues, and health & safety procedures. It is NOT primarily about teaching job skills, which is a very common student error."}'::jsonb),
('business:3-6-training-and-development:learn:db80c032', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Staff Development — Apprenticeships", "reading": "<p>An <strong>apprenticeship</strong> is a long-term development programme (typically 2–4 years) that combines on-the-job work experience with off-the-job study, leading to a vocational qualification. Apprentices are already employed and paid while they learn.</p>\n  <div class=\"case-study-box\">\n    <h4>Case Study: Redrow Homes</h4>\n    <p>Redrow Homes employs over 2,300 people and has been named a ''Top 100 Apprenticeship Employer'' for five consecutive years. At any one time, the company employs at least 130 apprentices in trades such as carpentry, plumbing, and bricklaying. Apprentices follow a clear career path, gaining qualifications alongside work experience and a competitive wage. The company views apprenticeships as an excellent way to find and develop motivated young staff tailored to the construction industry''s specific needs.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Business</div>\n      <div class=\"pro-item\"><strong>Tailored training:</strong> Learning is tailored to the firm''s specific needs — apprentices learn to do the job the business''s way.</div>\n      <div class=\"pro-item\"><strong>Cost-effective:</strong> Often cheaper than hiring already-skilled workers. Government subsidies may be available.</div>\n      <div class=\"pro-item\"><strong>Productive while training:</strong> Apprentices contribute work to the business as they learn.</div>\n      <div class=\"pro-item\"><strong>Loyalty and retention:</strong> Apprentices who feel invested in are more likely to stay with the business long-term.</div>\n      <div class=\"pro-item\"><strong>Solves skill shortages:</strong> Builds the specific skills the industry needs from within.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Business</div>\n      <div class=\"con-item\"><strong>Costly to run:</strong> Course fees, time of experienced workers acting as mentors, reduced output while apprentice is off-site studying.</div>\n      <div class=\"con-item\"><strong>Risk of quality issues:</strong> Apprentices not yet fully skilled may make mistakes, wasting resources.</div>\n      <div class=\"con-item\"><strong>Drop-out risk:</strong> If an apprentice does not complete the programme, the investment is wasted.</div>\n    </div>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Worker</div>\n      <div class=\"pro-item\">Earn a wage while learning — no need to take on student debt.</div>\n      <div class=\"pro-item\">Gain a recognised vocational qualification to support career progression.</div>\n      <div class=\"pro-item\">Varied learning — mix of practical and theoretical activities.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Worker</div>\n      <div class=\"con-item\">Pay is usually low during the apprenticeship period.</div>\n      <div class=\"con-item\">Qualifications are job-specific — may limit future career breadth compared to a degree.</div>\n      <div class=\"con-item\">Evidence suggests degree-holders earn more on average in the long run.</div>\n    </div>\n  </div>", "question": "Why does Redrow Homes view apprenticeships as valuable, according to the case study?", "options": ["They help find and develop motivated staff suited to construction", "Apprentices are not required to be paid", "Apprenticeships replace the need for any qualified tradespeople", "Apprentices only work part-time"]}'::jsonb, '{"answer": 0, "explain": "Redrow Homes uses apprenticeships to build a pipeline of skilled, loyal workers specifically suited to the construction trade — carpentry, plumbing, bricklaying — developed from within rather than recruited externally."}'::jsonb),
('business:3-6-training-and-development:learn:032f0816', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Staff Development — Professional Development Programmes", "reading": "<p><strong>Professional development programmes</strong> are long-term development activities (vocational or academic) designed to realise the long-term potential of a worker. They often lead to qualifications such as degrees, professional diplomas, or vocational certificates and are a form of staff development — not short-term training.</p>\n  <div class=\"case-study-box\">\n    <h4>Case Study: Capgemini</h4>\n    <p>Capgemini, a global technology consultancy operating in 40 countries, supports employees to work part-time towards a BSc in Software Engineering or BSc in Business Information Systems. These \"advanced apprenticeships\" develop the long-term potential of existing staff, helping Capgemini build a highly skilled, loyal workforce for the future.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Business</div>\n      <div class=\"pro-item\"><strong>Improves long-term productivity:</strong> Better-qualified workers perform more efficiently, helping the business compete.</div>\n      <div class=\"pro-item\"><strong>Workforce planning:</strong> Develops future managers internally — as senior workers leave, others are ready for promotion.</div>\n      <div class=\"pro-item\"><strong>Motivation and retention:</strong> Workers feel valued, work harder, and are less likely to leave.</div>\n      <div class=\"pro-item\"><strong>Attract high-quality recruits:</strong> Offering development opportunities makes the business more attractive to ambitious candidates.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Business</div>\n      <div class=\"con-item\"><strong>Expensive:</strong> Course fees, lost working time, and cover costs all add up.</div>\n      <div class=\"con-item\"><strong>Retention risk:</strong> Once qualified, workers may find it easier to secure higher-paid jobs at rival firms.</div>\n      <div class=\"con-item\"><strong>No guarantee of return:</strong> The business cannot guarantee the investment will benefit the firm if the worker leaves.</div>\n    </div>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Worker</div>\n      <div class=\"pro-item\">Gain qualifications and experience leading to career opportunities.</div>\n      <div class=\"pro-item\">Increased earnings potential and promotion prospects.</div>\n      <div class=\"pro-item\">Improved self-esteem — feels supported and valued by the employer.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Worker</div>\n      <div class=\"con-item\">Can be very demanding and stressful alongside a full-time job.</div>\n      <div class=\"con-item\">No guarantee the qualification will lead to career progression at that business.</div>\n    </div>\n  </div>", "question": "What is a key business risk of investing in professional development programmes for staff?", "options": ["Once qualified, workers may find better-paid jobs at rival firms", "Professional development always reduces staff motivation", "There is no risk at all — it is always a safe investment", "Workers are legally required to stay with the business for life"]}'::jsonb, '{"answer": 0, "explain": "A major risk is retention — after gaining a valuable qualification, a worker becomes more attractive to other employers and may leave, meaning the business does not always get a return on its investment."}'::jsonb),
('business:3-6-training-and-development:learn:0e41ac4d', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'learn', 'mcq', 1, '{"readingTitle": "Evaluation: Which Training Method is Best?", "reading": "<p>There is no single \"best\" training method — the right choice depends on the situation. In evaluation questions, always consider the context of the business.</p>\n  <ul>\n    <li><strong>On-the-job</strong> is best when: the work is straightforward, cost is a concern, and mistakes are recoverable. <em>Not suitable</em> when safety is critical or quality standards are very high.</li>\n    <li><strong>Off-the-job</strong> is best when: the work involves safety risks, specialist skills, or industry-regulated qualifications are required. <em>Not suitable</em> when the business cannot afford the cost or the worker''s absence.</li>\n    <li><strong>Induction</strong> is always needed for new starters — it reduces settling-in time and health and safety risks regardless of sector.</li>\n    <li><strong>Apprenticeships</strong> suit businesses that need specific, practical skills developed over time and want to build loyal, long-term employees. Best for trades, engineering, and technical roles.</li>\n    <li><strong>Professional development</strong> suits businesses with ambitious employees and a need for future managers or highly qualified specialists. Especially valuable in finance, law, technology, and healthcare.</li>\n  </ul>\n  <p><strong>Evaluation tip:</strong> Consider whether the business can afford the cost, whether the worker will stay after qualifying, and whether the skill needed is short-term or long-term. These are the factors that decide which method is best <em>in context</em>.</p>", "question": "When is off-the-job training NOT suitable for a business, according to this topic?", "options": ["When safety is critical or industry-regulated qualifications are required", "When the business cannot afford the cost or manage the worker''s absence", "Off-the-job training is always suitable in every situation", "When the worker has been employed for less than a year"]}'::jsonb, '{"answer": 1, "explain": "Off-the-job training is ideal for safety-critical or specialist roles, but it isn''t suitable when a business can''t afford the cost or the disruption of having the worker absent — the right method always depends on context."}'::jsonb),
('business:3-6-training-and-development:misc:36f045db', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Induction training teaches new workers how to do their job.</p><p><strong>✅ The correct idea:</strong> Induction training introduces the new worker to the business, workplace, colleagues, and health and safety rules. It is about settling in — not skill-building. Examiners specifically flagged this as a very common error.</p>", "question": "Does induction training primarily teach a new worker job-specific skills?", "options": ["Yes, that is its main purpose", "No — it''s about settling in, not job skills", "Yes, but only for management roles", "No, induction is only for experienced workers"]}'::jsonb, '{"answer": 1, "explain": "Induction is about helping a new worker settle in to the business — its purpose is not to teach job skills, which is a very commonly tested misconception."}'::jsonb),
('business:3-6-training-and-development:misc:37ebbb1a', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Training and development mean the same thing.</p><p><strong>✅ The correct idea:</strong> They are different. Training is short-term and job-specific. Development is long-term and about the overall growth of the worker''s potential. Always check which one the question is asking about.</p>", "question": "If an exam question specifically asks about ''development'', should you write about short-term, job-specific skills?", "options": ["Yes, training and development are interchangeable", "No — development means long-term growth, not skills", "Yes, as long as you mention training", "It doesn''t matter which term the question uses"]}'::jsonb, '{"answer": 1, "explain": "Training and development are distinct terms tested separately by examiners. Development questions need long-term, potential-focused answers — not short-term job-specific training answers."}'::jsonb),
('business:3-6-training-and-development:misc:c3c30c2c', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Off-the-job training is always better than on-the-job training.</p><p><strong>✅ The correct idea:</strong> Neither is universally better — it depends on the situation. On-the-job is cheaper and keeps the worker productive. Off-the-job is higher quality and safer for risky roles. Always evaluate in context.</p>", "question": "Is off-the-job training always the best choice for a business?", "options": ["Yes, it is always superior to on-the-job training", "No — it depends entirely on the business situation", "No, on-the-job training is always better", "Neither method is ever appropriate"]}'::jsonb, '{"answer": 1, "explain": "Neither method is universally better. The right choice depends on context — cost, safety requirements, and the nature of the skill being taught all matter."}'::jsonb),
('business:3-6-training-and-development:misc:e409dd48', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Apprenticeships are only for school leavers looking for their first job.</p><p><strong>✅ The correct idea:</strong> On this specification, apprenticeships are a form of staff development for existing employees. They reduce the time a worker spends on their normal duties while they study — they are not just a cheap way to recruit new workers.</p>", "question": "According to this specification, are apprenticeships only for school leavers seeking their first job?", "options": ["Yes, that is their only purpose", "No, they also develop existing employees at the firm", "Apprenticeships do not exist on this specification", "Apprenticeships are only for graduates"]}'::jsonb, '{"answer": 1, "explain": "Apprenticeships are presented as a staff development method that can apply to existing employees being developed within the business, not solely as a route into a first job."}'::jsonb),
('business:3-6-training-and-development:misc:0002c52b', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> On-the-job training means the same as internal training.</p><p><strong>✅ The correct idea:</strong> These are not the same. On-the-job and off-the-job refer to whether training takes place during normal work. Internal vs external refers to who delivers the training. Do not confuse location with method.</p>", "question": "What is the difference between ''on-the-job vs off-the-job'' and ''internal vs external'' training?", "options": ["They are the same distinction described two ways", "One is about when; the other is who delivers it", "Internal training is always on-the-job", "External training is always off-the-job"]}'::jsonb, '{"answer": 1, "explain": "These describe two completely different things: on/off-the-job is about whether training happens during normal duties, while internal/external is about who provides the training — they should not be confused."}'::jsonb),
('business:3-6-training-and-development:misc:a51f1b5d', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For an ''analyse one benefit to employees'' question, answers about increased profits or productivity are correct.</p><p><strong>✅ The correct idea:</strong> Profits and productivity are benefits to the BUSINESS, not the employee. When the question specifies employees, you must write about personal benefits — higher pay, promotion prospects, improved self-esteem, job satisfaction.</p>", "question": "If a question asks for a benefit to EMPLOYEES specifically, is ''increased profits'' a valid answer?", "options": ["Yes, profit is always a good answer", "No, profit benefits the business, not the employee", "Yes, as long as profit is mentioned somewhere", "No, because profit never increases from training"]}'::jsonb, '{"answer": 1, "explain": "Always check who the question is asking about. Profit and productivity are business-facing benefits — when the question specifies employees, you need employee-facing benefits like pay, promotion, or job satisfaction."}'::jsonb),
('business:3-6-training-and-development:misc:1371afe6', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Vocational qualifications are more general than academic qualifications.</p><p><strong>✅ The correct idea:</strong> It is the opposite. Vocational qualifications are job-specific (e.g. NVQs). Academic qualifications (e.g. GCSEs, degrees) are more general and can open up a wider range of career paths.</p>", "question": "Which type of qualification is more job-specific: vocational or academic?", "options": ["Academic qualifications are more job-specific", "Vocational qualifications are more job-specific", "They are equally general", "Neither type is job-specific"]}'::jsonb, '{"answer": 1, "explain": "Vocational qualifications (like NVQs) are tied to a specific job or trade, while academic qualifications (like GCSEs or degrees) are broader and can lead to a wider range of career paths."}'::jsonb),
('business:3-6-training-and-development:misc:750b00e1', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Staff development is just another word for training.</p><p><strong>✅ The correct idea:</strong> Staff development is broader and longer-term than training. It includes apprenticeships and professional development programmes that develop the worker''s overall potential, not just their ability to do the current job.</p>", "question": "Is staff development simply another term for training?", "options": ["Yes, they mean exactly the same thing", "No, it''s a broader, longer-term idea than training", "Yes, but only for senior staff", "No, staff development only applies to new employees"]}'::jsonb, '{"answer": 1, "explain": "Staff development is a wider, longer-term concept than training — it includes things like apprenticeships and professional qualifications aimed at growing a worker''s overall potential, not just their current job performance."}'::jsonb),
('business:3-6-training-and-development:tips:da0f442c', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Training Method Questions: Name It, Then Apply It", "reading": "\n        <p>When asked to <strong>explain a training method</strong> (e.g. \"Explain three methods of training HSBC may use\"), each method earns you <strong>2 marks: 1 for naming the method + 1 for applying it to the business</strong>.</p>\n        <p><strong>The Formula:</strong></p>\n        <ul>\n          <li><strong>Name the method</strong> (K): On-the-job training / Off-the-job training / Induction training</li>\n          <li><strong>Apply it to the business</strong> (APP): Link to a detail from the case study</li>\n        </ul>\n        <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n        <em>\"HSBC could use on-the-job training because it will help staff learn.\"</em><br/>\n        No application — too vague.</p>\n        <p><strong>✅ Good Answer (2 marks):</strong><br/>\n        <em>\"HSBC could use on-the-job training (K) to help call centre staff practise opening new bank accounts using HSBC''s own IT systems (APP).\"</em></p>\n        <p><strong>⚠️ Examiner Warning:</strong> Do NOT write \"online training\" or \"at-home training\" as a third method — these are not the correct terms. The three methods are: <strong>on-the-job, off-the-job, and induction</strong>. Induction was the most commonly missed method.</p>\n        <p><strong>🚫 Do NOT accept:</strong> \"on-site\", \"off-site\", \"internal\", or \"external\" training — these describe location, not the training method itself.</p>\n      ", "question": "Which three training methods are the correct answers when asked to name training methods a business could use?", "options": ["On-site, off-site, and internal training", "On-the-job, off-the-job, and induction", "Internal, external, and online", "Apprenticeship, degree, and NVQ"]}'::jsonb, '{"answer": 1, "explain": "The three correct training methods on this specification are on-the-job, off-the-job, and induction. Induction is the one most commonly missed by students — terms like ''internal'' or ''on-site'' describe location, not the method itself."}'::jsonb),
('business:3-6-training-and-development:tips:fd3a6859', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n        <p>Every 3-mark analyse question needs exactly three things in a chain of reasoning. Miss any one and you cap yourself at 2 marks.</p>\n        <p><strong>Step-by-Step Formula:</strong></p>\n        <ul>\n          <li><strong>1. Understanding (U):</strong> State and explain the benefit or reason.</li>\n          <li><strong>2. Application (APP):</strong> Link directly to the specific business in the case study using a detail from the text.</li>\n          <li><strong>3. Analysis (AN):</strong> State the business-facing (or employee-facing) impact — cost, revenue, profit, reputation, retention, etc.</li>\n        </ul>\n        <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n        <em>\"Training improves customer service which increases profits.\"</em><br/>\n        No application to the specific business — this could be about any firm.</p>\n        <p><strong>✅ Full Mark Answer (3 marks):</strong><br/>\n        <em>\"Training will improve the customer service skills of staff (U). This is especially important at Waitrose, which targets customers with higher income levels and a reputation for quality (APP). As a result, customers are more likely to be satisfied and return, boosting sales revenue (AN).\"</em></p>\n        <p><strong>⚠️ Critical Examiner Warning — Check Who Benefits:</strong> If the question asks for a benefit to <strong>employees</strong>, your analysis must be <em>employee-facing</em> (e.g. higher pay, promotion, job satisfaction). If the question asks about the <strong>business</strong>, your analysis must be <em>business-facing</em> (e.g. profit, retention, productivity). Writing business benefits when asked about employees scores zero for analysis.</p>\n        <p><strong>Useful sentence starters:</strong></p>\n        <ul>\n          <li><em>U: \"Off-the-job training allows workers to be trained by specialists...\"</em></li>\n          <li><em>APP: \"In the case of [Business], this is important because the text states that...\"</em></li>\n          <li><em>AN: \"As a result, the business will... / This will lead to... / This means profits will...\"</em></li>\n        </ul>\n      ", "question": "Why does the answer ''Training improves customer service which increases profits'' score only 1 mark on a 3-mark analyse question?", "options": ["It is too long", "It has no application to the specific business", "It mentions profit, which is not relevant", "Customer service is not connected to training"]}'::jsonb, '{"answer": 1, "explain": "Without applying the point to the named business using a specific case study detail, you cannot score the APP or AN marks — the chain breaks before it reaches analysis."}'::jsonb),
('business:3-6-training-and-development:tips:2bd3e7f8', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Benefits — 6 marks — Two Separate Chains — No Conclusion Needed", "reading": "\n        <p>A 6-mark \"analyse two benefits\" question is simply the 3-mark structure done <strong>twice</strong>. Each benefit earns up to 3 marks (U + APP + AN).</p>\n        <p><strong>Key Rules:</strong></p>\n        <ul>\n          <li>Write two fully separate chains of reasoning — do not mix them together.</li>\n          <li>Both benefits must relate to the <strong>method</strong> asked about (e.g. off-the-job training specifically), not to training in general.</li>\n          <li><strong>Do NOT write a conclusion</strong> — there are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</li>\n          <li>Apply each benefit to the case study business using a specific detail from the text.</li>\n        </ul>\n        <p><strong>⚠️ Examiner Warning (BFF question):</strong> Do not write about motivation or productivity as a benefit of off-the-job training — these apply to <em>all</em> types of training. You must identify a feature <em>specific to off-the-job training</em>, such as training by an expert, use of specialist equipment, or a safe environment to practise.</p>\n        <p><strong>Structure:</strong><br/>\n        <em>Benefit 1: [U — specialist feature of off-the-job] → [APP — apply to BFF] → [AN — business impact]</em><br/>\n        <em>Benefit 2: [U — another specific feature] → [APP — apply to BFF] → [AN — business impact]</em></p>\n      ", "question": "On a 6-mark ''analyse two benefits of off-the-job training'' question, why would writing about ''improved motivation'' score zero for the second benefit?", "options": ["Motivation is not relevant to any type of training", "Motivation isn''t a feature unique to off-the-job training", "Six-mark questions do not award marks for motivation points", "You can only write one benefit, not two"]}'::jsonb, '{"answer": 1, "explain": "The question asks specifically about off-the-job training — so your benefits must be features unique to it (expert trainers, specialist equipment, safe environment). Generic training benefits like motivation could apply to any method and will not score."}'::jsonb),
('business:3-6-training-and-development:tips:27c4e229', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Both Sides + A Justified, Contextual Decision", "reading": "\n        <p>A 7-mark evaluate question is marked independently across three skill areas: <strong>Application (2), Analysis (2), and Evaluation (3)</strong>. No skill is a pre-requisite of another — you can pick up marks in any area independently.</p>\n        <p><strong>The 3-Paragraph Structure:</strong></p>\n        <ol>\n          <li><strong>Paragraph 1 (AN + APP):</strong> Analyse one advantage of the method/strategy using a case study detail.</li>\n          <li><strong>Paragraph 2 (AN + APP):</strong> Analyse one disadvantage of the method/strategy using a case study detail.</li>\n          <li><strong>Paragraph 3 (Evaluation — 3 sentences):</strong>\n            <ul>\n              <li><strong>Decision:</strong> \"Overall, Dyson Ltd should/should not continue with apprenticeships because...\"</li>\n              <li><strong>Context:</strong> Link your decision to a specific detail from the case study.</li>\n              <li><strong>Impact/Reasoning:</strong> Explain the consequence of that decision for the business.</li>\n            </ul>\n          </li>\n        </ol>\n        <p><strong>Evaluation Marks Breakdown:</strong></p>\n        <ul>\n          <li><strong>1 mark (Limited):</strong> Just a decision — \"Dyson should continue with apprenticeships.\"</li>\n          <li><strong>2 marks (Good):</strong> Decision + non-contextual justification.</li>\n          <li><strong>3 marks (Strong):</strong> Decision + justified using a specific detail from the case study.</li>\n        </ul>\n        <p><strong>✅ Strong Evaluation Example:</strong><br/>\n        <em>\"Overall, Dyson Ltd should continue offering apprenticeships (DECISION) as James Dyson personally promotes careers in engineering and the company creates innovative products (CONTEXT). Apprenticeships allow Dyson to develop engineers with the exact skills needed for product innovation, giving the business a long-term competitive advantage (REASONING).\"</em></p>\n        <p><strong>⚠️ Examiner Warning (Dyson question):</strong> Many students wrote about the advantages/disadvantages to the apprentice rather than to Dyson. Always re-read: the question asks about the business''s perspective. Also, answers about taking on apprentices as cheap new recruits were wrong — the question was about apprenticeships as a method of developing existing staff.</p>\n      ", "question": "How many marks is a strong evaluation conclusion worth in a 7-mark question, and what three things must it include?", "options": ["1 mark — just a decision", "3 marks — decision, detail, reasoning", "2 marks — two advantages", "3 marks — three separate advantages"]}'::jsonb, '{"answer": 1, "explain": "The evaluation element is worth up to 3 marks. A strong conclusion (3 marks) must include: a clear decision, a specific detail from the case study, and reasoning explaining the consequence for that particular business."}'::jsonb),
('business:3-6-training-and-development:tips:943e0986', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tips', 'mcq', 1, '{"readingTitle": "Identify — 1 mark — Staff Development vs Training: Know the Difference", "reading": "\n        <p>When asked to \"identify two other methods of staff development\", be careful — many students write training methods instead.</p>\n        <p><strong>Staff Development methods (correct answers):</strong></p>\n        <ul>\n          <li>Academic qualifications (e.g. GCSEs, A Levels, degrees)</li>\n          <li>Vocational qualifications (e.g. NVQs, Cambridge Technicals)</li>\n          <li>Professional development programmes</li>\n          <li>Secondments</li>\n        </ul>\n        <p><strong>🚫 Do NOT write these — they are training methods, not staff development:</strong></p>\n        <ul>\n          <li>On-the-job training</li>\n          <li>Off-the-job training</li>\n          <li>Induction</li>\n          <li>Courses (too vague)</li>\n        </ul>\n        <p>If the question says \"other than apprenticeships\", do not repeat apprenticeships — write something from the list above.</p>\n      ", "question": "If asked to ''identify two methods of staff development other than apprenticeships'', which of the following is a correct answer?", "options": ["On-the-job skills training", "Induction training", "Vocational qualifications", "Off-the-job training"]}'::jsonb, '{"answer": 2, "explain": "On-the-job training, induction, and off-the-job training are all training methods — not staff development. Correct staff development methods include vocational qualifications, academic qualifications, professional development programmes, and secondments."}'::jsonb),
('business:3-6-training-and-development:tips:95d73cfb', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Make a Clear Choice and Compare Both Options", "reading": "\n        <p>A \"recommend\" question requires you to make a <strong>clear decision</strong> AND justify it by comparing it to the alternative. Simply describing one option without comparing is not enough.</p>\n        <p><strong>Formula:</strong></p>\n        <ul>\n          <li><strong>Judgement (1 mark):</strong> State clearly which option you recommend.</li>\n          <li><strong>Contextual justification (2 marks):</strong> Explain why your choice is better THAN the other, using a detail from the case study.</li>\n        </ul>\n        <p><strong>Example (McDonald''s training question):</strong></p>\n        <p><strong>❌ Weak (1 mark):</strong><br/>\n        <em>\"McDonald''s should use induction training because James is new.\"</em></p>\n        <p><strong>✅ Strong (3 marks):</strong><br/>\n        <em>\"McDonald''s should use induction training (JUDGEMENT) because James has never worked for McDonald''s before, so he needs to understand the company''s procedures, where the fire exits are, and how he will be paid (CONTEXT). Unlike on-the-job training, induction doesn''t risk dangerous mistakes while James is still learning the basics (COMPARISON).\"</em></p>\n      ", "question": "What is missing from this Recommend answer: ''McDonald''s should use induction training because James is new''?", "options": ["Nothing — it scores all 3 marks", "A comparison to the alternative method", "A definition of induction training", "A calculation"]}'::jsonb, '{"answer": 1, "explain": "This answer gives a basic judgement (1 mark) but needs a contextual justification using case study detail AND a comparison with the alternative method to reach full marks — simply saying James is new is not enough."}'::jsonb),
('business:3-6-training-and-development:fib:9dfe7420', 'business', 'business:3-6-training-and-development', '3.6 Training and Development', 'fib', 'fib', 2, '{"question": "Training is _____ and job-specific, while development is _____ and focused on the overall growth of the worker.", "blankOptions": {"B1": ["short-term", "safe", "retention", "on-the-job"], "B2": ["long-term", "retention", "vocational", "trainer"]}}'::jsonb, '{"blanks": {"B1": "short-term", "B2": "long-term"}}'::jsonb),
